  Edit: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M16.862 4.487l1.687-1.688a1.875 1.875 0 112.652 2.652L10.582 16.07a4.5 4.5 0 01-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 011.13-1.897l8.932-8.931zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0115.75 21H5.25A2.25 2.25 0 013 18.75V8.25A2.25 2.25 0 015.25 6H10" /></svg>,
  Save: () => <svg width="18" height="18" fill="none" stroke="white" strokeWidth="1.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>,
  Delete: () => <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M14.74 9l-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 01-2.244 2.077H8.084a2.25 2.25 0 01-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 00-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 013.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 00-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 00-7.5 0" /></svg>,
  Add: () => <svg width="18" height="18" fill="none" stroke="white" strokeWidth="1.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" /></svg>
};

const StaffManager = () => {
  const { user } = useAuth();
  const { staffList, addStaff, deleteStaff, updateStaffInfo } = useData();
  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  const [editMode, setEditMode] = useState(null);
  const [editForm, setEditForm] = useState({});

  const isChief = user?.role === 'chief';
  
  const roleName = (r) => {
      if(r==='chief') return 'Chief Admin';
      if(r==='reg') return 'Reg Admin';
      if(r==='op') return 'Op Admin';
      return 'Staff';
  };

  const handleAdd = (e) => {
    e.preventDefault();
    if (!formData.name || !formData.username || !formData.password) return;
    addStaff({ 
        ...formData, 
        role: 'staff', 
        positions: [], 
        ubi1Base: 0, ubi1Percent: 100,
        ubi2Base: 0, ubi2Percent: 100,
        remuneration: 0,
        status: 'active' 
    });
    setFormData({ name: '', username: '', password: '' });
  };

  const startEdit = (staff) => {
    setEditMode(staff.id);
    setEditForm({ ...staff, newPassword: '' }); 
  };

  const saveEdit = (id) => {
    const { newPassword, ...rest } = editForm;
    const updates = { ...rest };
    if (newPassword && newPassword.trim() !== '') updates.password = newPassword;
    updateStaffInfo(id, updates);
    setEditMode(null);
  };

  const handlePositionToggle = (pos) => {
    const current = editForm.positions || [];
    setEditForm({ ...editForm, positions: current.includes(pos) ? current.filter(p => p !== pos) : [...current, pos] });
  };

  if (!isChief) return <div style={{padding:'20px', color:'#d32f2f'}}>Bạn không có quyền truy cập quản lý nhân sự cấp cao.</div>;

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '1px solid #e0e0e0', paddingBottom: '15px' }}>Quản lý Nhân sự (Chief Only)</h2>

      {/* FORM TẠO MỚI */}
      <div style={{ background: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', marginBottom: '25px' }}>
        <form onSubmit={handleAdd} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
          <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} required style={styles.input} />
          <input placeholder="Username" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} required style={styles.input} />
          <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} required style={styles.input} />
          <button type="submit" style={styles.btnAdd}><Icons.Add /> Tạo mới</button>
        </form>
      </div>

      {/* DANH SÁCH */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))', gap: '20px' }}>
        {staffList.map(staff => (
          <div key={staff.id} style={{ 
              background: 'white', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.06)', padding: '20px', 
              border: editMode === staff.id ? '2px solid #003366' : '1px solid #f0f0f0'
          }}>
            <div style={{ fontWeight: 'bold', fontSize: '1.1rem', color: '#111827' }}>{staff.name}</div>
            <div style={{ fontSize: '0.8rem', color: '#6b7280', marginBottom: '10px' }}>@{staff.username} - {roleName(staff.role)}</div>

            {editMode === staff.id ? (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                    <select value={editForm.role} onChange={e => setEditForm({...editForm, role: e.target.value})} style={styles.inputFull}>
                        <option value="staff">Staff</option><option value="op">Op Admin</option><option value="reg">Reg Admin</option><option value="chief">Chief Admin</option>
                    </select>
                    <div style={{display:'flex', flexWrap:'wrap', gap:'6px'}}>
                        {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => (
                            <label key={r} style={styles.checkboxLabel}>
                                <input type="checkbox" checked={editForm.positions?.includes(r)} onChange={() => handlePositionToggle(r)}/> {r}
                            </label>
                        ))}
                    </div>
                    {/* TÀI CHÍNH CHI TIẾT */}
                    <div style={{background: '#f9fafb', padding: '10px', borderRadius: '6px'}}>
                        <div style={styles.financeLabel}>UBI 1 (Cơ bản & Tỷ lệ)</div>
                        <div style={{display:'flex', gap:'5px'}}>
                            <input type="number" value={editForm.ubi1Base} onChange={e => setEditForm({...editForm, ubi1Base: Number(e.target.value)})} placeholder="UBI 1 Base" style={styles.inputFull}/>
                            <input type="number" value={editForm.ubi1Percent} onChange={e => setEditForm({...editForm, ubi1Percent: Number(e.target.value)})} placeholder="%" style={{...styles.inputFull, width: '60px'}}/>
                        </div>
                        <div style={styles.financeLabel}>UBI 2 (Hiệu suất & Tỷ lệ)</div>
                        <div style={{display:'flex', gap:'5px'}}>
                            <input type="number" value={editForm.ubi2Base} onChange={e => setEditForm({...editForm, ubi2Base: Number(e.target.value)})} placeholder="UBI 2 Base" style={styles.inputFull}/>
                            <input type="number" value={editForm.ubi2Percent} onChange={e => setEditForm({...editForm, ubi2Percent: Number(e.target.value)})} placeholder="%" style={{...styles.inputFull, width: '60px'}}/>
                        </div>
                        <div style={styles.financeLabel}>Remuneration</div>
                        <input type="number" value={editForm.remuneration} onChange={e => setEditForm({...editForm, remuneration: Number(e.target.value)})} placeholder="Thù lao" style={styles.inputFull}/>
                    </div>
                    <div style={{display:'flex', gap:'8px'}}>
                        <button onClick={() => saveEdit(staff.id)} style={styles.btnSave}>Lưu</button>
                        <button onClick={() => setEditMode(null)} style={styles.btnCancel}>Hủy</button>
                    </div>
                </div>
            ) : (
                <div>
                     <div style={{ fontSize: '0.85rem', color: '#374151', background: '#f3f4f6', padding: '8px', borderRadius: '4px', marginTop: '10px' }}>
                        <div><strong>UBI 1:</strong> {(staff.ubi1Base || 0).toLocaleString()} ({staff.ubi1Percent}%)</div>
                        <div><strong>UBI 2:</strong> {(staff.ubi2Base || 0).toLocaleString()} ({staff.ubi2Percent}%)</div>
                        <div><strong>Remuneration:</strong> {(staff.remuneration || 0).toLocaleString()}</div>
                     </div>
                     <div style={{marginTop:'15px', display:'flex', gap:'10px'}}>
                        <button onClick={() => startEdit(staff)} style={styles.btnEdit}>Sửa</button>
                        <button onClick={() => { if(window.confirm('Xóa?')) deleteStaff(staff.id) }} style={styles.btnDelete}>Xóa</button>
                     </div>
                </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
    input: { padding: '10px', border: '1px solid #ccc', borderRadius: '4px', flex: 1 },
    inputFull: { padding: '8px', border: '1px solid #ccc', borderRadius: '4px', width: '100%', marginBottom: '5px' },
    checkboxLabel: { fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '4px', background: '#eee', padding: '2px 6px', borderRadius: '4px' },
    financeLabel: { fontSize: '0.75rem', fontWeight: 'bold', color: '#555', marginTop: '8px', marginBottom: '2px' },
    btnAdd: { background: '#003366', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '4px', cursor: 'pointer', display: 'flex', gap: '5px' },
    btnSave: { background: '#059669', color: 'white', padding: '6px 12px', border: 'none', borderRadius: '4px', cursor: 'pointer', flex: 1 },
    btnCancel: { background: '#9ca3af', color: 'white', padding: '6px 12px', border: 'none', borderRadius: '4px', cursor: 'pointer' },
    btnEdit: { background: 'white', border: '1px solid #003366', color: '#003366', padding: '5px 15px', borderRadius: '4px', cursor: 'pointer' },
    btnDelete: { background: 'white', border: '1px solid red', color: 'red', padding: '5px 15px', borderRadius: '4px', cursor: 'pointer' }
};

export default StaffManager;
